public int active()
{
    int ret = next active(); 

    if(ETGACFParameters::find().EnableTradeLimit == NoYes::Yes)
    {
        VendTable       vendTable       = this.cursor();
        FormRealControl tradeLimitField = this.formRun().design().controlName(formControlStr(VendTable, ETGTradeLimit_ETGTradeLimitInVendorCurrency));
        if (tradeLimitField)
        {
            tradeLimitField.label(strFmt("Trade limit in vendor currency(%1)", vendTable.Currency));
        }
    }

    // Freezes the form fields by updating the design when the data source is activated.
    ETGDMSIntegrationFormDesignHelper::updateDesignDMS(this);
    //
    return ret;

}
